package com.google.devtools.build.lib.packages;

import static com.google.common.truth.Truth.assertThat;
import static com.google.common.truth.Truth.assertWithMessage;
import static org.junit.Assert.assertThrows;

import com.google.common.collect.ImmutableList;
import com.google.devtools.build.lib.analysis.ConfiguredRuleClassProvider;
import com.google.devtools.build.lib.cmdline.Label;
import com.google.devtools.build.lib.cmdline.PackageIdentifier;
import com.google.devtools.build.lib.cmdline.RepositoryMapping;
import com.google.devtools.build.lib.packages.RuleFactory.BuildLangTypedAttributeValuesMap;
import com.google.devtools.build.lib.packages.util.PackageLoadingTestCase;
import com.google.devtools.build.lib.testutil.TestRuleClassProvider;
import com.google.devtools.build.lib.vfs.Path;
import com.google.devtools.build.lib.vfs.RootedPath;
import java.util.HashMap;
import java.util.Map;
import java.util.Optional;
import net.starlark.java.eval.StarlarkSemantics;
import net.starlark.java.eval.StarlarkThread;
import net.starlark.java.syntax.Location;
import org.junit.Test;
import org.junit.runner.RunWith;
import org.junit.runners.JUnit4;

/**
 * Comprehensive unit tests for Starlark rule evaluation, including rule instantiation, attribute
 * validation, and error handling.
 */
@RunWith(JUnit4.class)
public final class StarlarkRuleEvalTest extends PackageLoadingTestCase {

  private final ConfiguredRuleClassProvider provider = TestRuleClassProvider.getRuleClassProvider();

  private static final ImmutableList<StarlarkThread.CallStackEntry> DUMMY_STACK =
      ImmutableList.of(
          StarlarkThread.callStackEntry(
              StarlarkThread.TOP_LEVEL, Location.fromFileLineColumn("BUILD", 42, 1)),
          StarlarkThread.callStackEntry("foo", Location.fromFileLineColumn("foo.bzl", 10, 1)),
          StarlarkThread.callStackEntry("myrule", Location.fromFileLineColumn("bar.bzl", 30, 6)));

  private Package.Builder newBuilder(PackageIdentifier id, Path filename) {
    return packageFactory
        .newPackageBuilder(
            id,
            RootedPath.toRootedPath(root, filename),
            "TESTING",
            Optional.empty(),
            Optional.empty(),
            StarlarkSemantics.DEFAULT,
            /* repositoryMapping= */ RepositoryMapping.ALWAYS_FALLBACK,
            /* mainRepositoryMapping= */ null,
            /* cpuBoundSemaphore= */ null,
            /* generatorMap= */ null,
            /* configSettingVisibilityPolicy= */ null,
            /* globber= */ null)
        .setLoads(ImmutableList.of());
  }

  /**
   * Test 1: Basic rule instantiation with required attributes.
   *
   * <p>This test verifies that a rule can be successfully created with all required attributes
   * provided.
   */
  @Test
  public void testBasicRuleInstantiationWithRequiredAttributes() throws Exception {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "my_genrule");
    attributeValues.put("outs", ImmutableList.of("output.txt"));
    attributeValues.put("cmd", "echo 'hello' > $@");

    RuleClass ruleClass = provider.getRuleClassMap().get("genrule");
    Rule rule =
        RuleFactory.createAndAddRule(
            pkgBuilder,
            ruleClass,
            new BuildLangTypedAttributeValuesMap(attributeValues),
            true,
            DUMMY_STACK);

    assertThat(rule.getName()).isEqualTo("my_genrule");
    assertThat(rule.getRuleClass()).isEqualTo("genrule");
    assertThat(rule.containsErrors()).isFalse();

    Package pkg = pkgBuilder.build();
    assertThat(pkg.getTarget("my_genrule")).isSameInstanceAs(rule);
  }

  /**
   * Test 2: Missing required attribute produces error.
   *
   * <p>This test verifies that creating a rule without the required "name" attribute raises an
   * InvalidRuleException.
   */
  @Test
  public void testMissingNameAttributeProducesError() {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    // Intentionally omit "name" attribute
    attributeValues.put("outs", ImmutableList.of("output.txt"));
    attributeValues.put("cmd", "echo 'hello' > $@");

    RuleClass ruleClass = provider.getRuleClassMap().get("genrule");

    RuleFactory.InvalidRuleException e =
        assertThrows(
            RuleFactory.InvalidRuleException.class,
            () ->
                RuleFactory.createAndAddRule(
                    pkgBuilder,
                    ruleClass,
                    new BuildLangTypedAttributeValuesMap(attributeValues),
                    true,
                    DUMMY_STACK));

    assertThat(e).hasMessageThat().contains("has no 'name' attribute");
  }

  /**
   * Test 3: Invalid name attribute type produces error.
   *
   * <p>This test verifies that providing a non-string value for the "name" attribute raises an
   * InvalidRuleException.
   */
  @Test
  public void testInvalidNameAttributeType() {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", 123); // Invalid: should be string
    attributeValues.put("outs", ImmutableList.of("output.txt"));
    attributeValues.put("cmd", "echo 'hello' > $@");

    RuleClass ruleClass = provider.getRuleClassMap().get("genrule");

    RuleFactory.InvalidRuleException e =
        assertThrows(
            RuleFactory.InvalidRuleException.class,
            () ->
                RuleFactory.createAndAddRule(
                    pkgBuilder,
                    ruleClass,
                    new BuildLangTypedAttributeValuesMap(attributeValues),
                    true,
                    DUMMY_STACK));

    assertThat(e).hasMessageThat().contains("'name' attribute must be a string");
  }

  /**
   * Test 4: Rule name validation - valid names.
   *
   * <p>This test verifies that rules can be created with various valid names.
   */
  @Test
  public void testValidRuleNames() throws Exception {
    String[] validNames = {"my_rule", "rule123", "a", "my_rule_123", "Rule"};

    for (String name : validNames) {
      Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
      Package.Builder pkgBuilder =
          newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

      Map<String, Object> attributeValues = new HashMap<>();
      attributeValues.put("name", name);
      attributeValues.put("outs", ImmutableList.of("output.txt"));
      attributeValues.put("cmd", "echo 'hello' > $@");

      RuleClass ruleClass = provider.getRuleClassMap().get("genrule");
      Rule rule =
          RuleFactory.createAndAddRule(
              pkgBuilder,
              ruleClass,
              new BuildLangTypedAttributeValuesMap(attributeValues),
              true,
              DUMMY_STACK);

      assertThat(rule.getName()).isEqualTo(name);
      assertThat(rule.containsErrors()).isFalse();
    }
  }

  /**
   * Test 5: Rule name validation - invalid names.
   *
   * <p>This test verifies that rules cannot be created with invalid names (e.g., names with
   * special characters that violate label syntax).
   */
  @Test
  public void testInvalidRuleNames() {
    String[] invalidNames = {"my-rule", "my rule", "my.rule", "my/../rule", ""};

    for (String name : invalidNames) {
      Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
      Package.Builder pkgBuilder =
          newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

      Map<String, Object> attributeValues = new HashMap<>();
      attributeValues.put("name", name);
      attributeValues.put("outs", ImmutableList.of("output.txt"));
      attributeValues.put("cmd", "echo 'hello' > $@");

      RuleClass ruleClass = provider.getRuleClassMap().get("genrule");

      RuleFactory.InvalidRuleException e =
          assertThrows(
              RuleFactory.InvalidRuleException.class,
              () ->
                  RuleFactory.createAndAddRule(
                      pkgBuilder,
                      ruleClass,
                      new BuildLangTypedAttributeValuesMap(attributeValues),
                      true,
                      DUMMY_STACK));

      assertThat(e).hasMessageThat().contains("illegal rule name");
    }
  }

  /**
   * Test 6: Default attribute values are applied.
   *
   * <p>This test verifies that attributes with default values are correctly populated when not
   * explicitly provided.
   */
  @Test
  public void testDefaultAttributeValuesAreApplied() throws Exception {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "my_cc_library");
    // Don't provide optional attributes with defaults

    RuleClass ruleClass = provider.getRuleClassMap().get("cc_library");
    Rule rule =
        RuleFactory.createAndAddRule(
            pkgBuilder,
            ruleClass,
            new BuildLangTypedAttributeValuesMap(attributeValues),
            true,
            DUMMY_STACK);

    Package pkg = pkgBuilder.build();
    Rule retrievedRule = pkg.getRule("my_cc_library");

    // Verify default values are applied
    AttributeMap attributes = RawAttributeMapper.of(retrievedRule);
    // cc_library has alwayslink default = false
    assertThat(attributes.get("alwayslink", Type.BOOLEAN)).isFalse();
    // cc_library has srcs default = []
    assertThat(attributes.get("srcs", BuildType.LABEL_LIST)).isEmpty();
  }

  /**
   * Test 7: Attribute type validation - string vs list.
   *
   * <p>This test verifies that attributes with string types and list types are properly
   * validated.
   */
  @Test
  public void testAttributeTypeValidation() throws Exception {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    // Create a genrule with both string (cmd) and list (outs) attributes
    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "typed_rule");
    attributeValues.put("cmd", "echo hello"); // String attribute
    attributeValues.put("outs", ImmutableList.of("out1.txt", "out2.txt")); // List attribute

    RuleClass ruleClass = provider.getRuleClassMap().get("genrule");
    Rule rule =
        RuleFactory.createAndAddRule(
            pkgBuilder,
            ruleClass,
            new BuildLangTypedAttributeValuesMap(attributeValues),
            true,
            DUMMY_STACK);

    AttributeMap attributes = RawAttributeMapper.of(rule);

    // Verify string attribute
    assertThat(attributes.get("cmd", Type.STRING)).isEqualTo("echo hello");

    // Verify list attribute
    assertThat(attributes.get("outs", BuildType.OUTPUT_LIST)).hasSize(2);
  }

  /**
   * Test 8: Label attribute type validation.
   *
   * <p>This test verifies that label attributes are properly handled.
   */
  @Test
  public void testLabelAttributeValidation() throws Exception {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "my_java_binary");
    attributeValues.put("srcs", ImmutableList.of(":Main.java"));
    attributeValues.put("main_class", "com.example.Main");

    RuleClass ruleClass = provider.getRuleClassMap().get("java_binary");
    Rule rule =
        RuleFactory.createAndAddRule(
            pkgBuilder,
            ruleClass,
            new BuildLangTypedAttributeValuesMap(attributeValues),
            true,
            DUMMY_STACK);

    assertThat(rule.getName()).isEqualTo("my_java_binary");
    assertThat(rule.containsErrors()).isFalse();
  }

  /**
   * Test 9: Visibility attribute handling - public.
   *
   * <p>This test verifies that visibility is correctly set to public.
   */
  @Test
  public void testVisibilityAttributeHandling_Public() throws Exception {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "public_rule");
    attributeValues.put("visibility", ImmutableList.of("//visibility:public"));

    RuleClass ruleClass = provider.getRuleClassMap().get("cc_library");
    Rule rule =
        RuleFactory.createAndAddRule(
            pkgBuilder,
            ruleClass,
            new BuildLangTypedAttributeValuesMap(attributeValues),
            true,
            DUMMY_STACK);

    Package pkg = pkgBuilder.build();
    Rule retrievedRule = pkg.getRule("public_rule");

    assertThat(retrievedRule.getVisibility()).isEqualTo(RuleVisibility.PUBLIC);
  }

  /**
   * Test 10: Visibility attribute handling - private.
   *
   * <p>This test verifies that visibility is correctly set to private.
   */
  @Test
  public void testVisibilityAttributeHandling_Private() throws Exception {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
