    RuleClass ruleClass = provider.getRuleClassMap().get("cc_library");
    Rule rule =
        RuleFactory.createAndAddRule(
            pkgBuilder,
            ruleClass,
            new BuildLangTypedAttributeValuesMap(attributeValues),
            true,
            DUMMY_STACK);

    Package pkg = pkgBuilder.build();
    Rule retrievedRule = pkg.getRule("private_rule");

    assertThat(retrievedRule.getVisibility()).isEqualTo(RuleVisibility.PRIVATE);
  }

  /**
   * Test 11: Visibility attribute handling - package group.
   *
   * <p>This test verifies that visibility can be set to specific package groups.
   */
  @Test
  public void testVisibilityAttributeHandling_PackageGroup() throws Exception {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "restricted_rule");
    attributeValues.put("visibility", ImmutableList.of("//other:group"));

    RuleClass ruleClass = provider.getRuleClassMap().get("cc_library");
    Rule rule =
        RuleFactory.createAndAddRule(
            pkgBuilder,
            ruleClass,
            new BuildLangTypedAttributeValuesMap(attributeValues),
            true,
            DUMMY_STACK);

    assertThat(rule.getName()).isEqualTo("restricted_rule");
    assertThat(rule.containsErrors()).isFalse();
  }

  /**
   * Test 12: Test rule special handling.
   *
   * <p>This test verifies that test rules have the testonly attribute set to true by default.
   */
  @Test
  public void testTestRuleSpecialHandling() throws Exception {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "my_test");
    attributeValues.put("srcs", ImmutableList.of("test.cc"));

    RuleClass ruleClass = provider.getRuleClassMap().get("cc_test");
    Rule rule =
        RuleFactory.createAndAddRule(
            pkgBuilder,
            ruleClass,
            new BuildLangTypedAttributeValuesMap(attributeValues),
            true,
            DUMMY_STACK);

    Package pkg = pkgBuilder.build();
    Rule retrievedRule = pkg.getRule("my_test");
    AttributeMap attributes = RawAttributeMapper.of(retrievedRule);

    // Test rules should have testonly = true
    assertThat(attributes.get("testonly", Type.BOOLEAN)).isTrue();
  }

  /**
   * Test 13: Workspace rules validation.
   *
   * <p>This test verifies that workspace rules (like bind) cannot be created in BUILD files.
   */
  @Test
  public void testWorkspaceRuleFailsInBuildFile() {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "workspace_rule");
    attributeValues.put("actual", "//foo:bar");

    RuleClass ruleClass = provider.getRuleClassMap().get("bind");

    RuleFactory.InvalidRuleException e =
        assertThrows(
            RuleFactory.InvalidRuleException.class,
            () ->
                RuleFactory.createAndAddRule(
                    pkgBuilder,
                    ruleClass,
                    new BuildLangTypedAttributeValuesMap(attributeValues),
                    true,
                    DUMMY_STACK));

    assertThat(e).hasMessageThat().contains("must be in the WORKSPACE file");
  }

  /**
   * Test 14: Build rules validation.
   *
   * <p>This test verifies that normal build rules cannot be created in WORKSPACE files.
   */
  @Test
  public void testBuildRuleFailsInWorkspaceFile() {
    Path myPkgPath = scratch.resolve("/workspace/WORKSPACE");
    Package.Builder pkgBuilder =
        newBuilder(
            PackageIdentifier.DEFAULT_REPOSITORY_PACKAGE, myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
