    RuleClass ruleClass = provider.getRuleClassMap().get("cc_library");

    RuleFactory.InvalidRuleException e =
        assertThrows(
            RuleFactory.InvalidRuleException.class,
            () ->
                RuleFactory.createAndAddRule(
                    pkgBuilder,
                    ruleClass,
                    new BuildLangTypedAttributeValuesMap(attributeValues),
                    true,
                    DUMMY_STACK));

    assertThat(e).hasMessageThat().contains("cannot be in the WORKSPACE file");
  }

  /**
   * Test 15: Rule added to package.
   *
   * <p>This test verifies that created rules are properly added to the package.
   */
  @Test
  public void testRuleAddedToPackage() throws Exception {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "rule1");
    attributeValues.put("outs", ImmutableList.of("out.txt"));
    attributeValues.put("cmd", "echo");

    RuleClass ruleClass = provider.getRuleClassMap().get("genrule");
    Rule rule1 =
        RuleFactory.createAndAddRule(
            pkgBuilder,
            ruleClass,
            new BuildLangTypedAttributeValuesMap(attributeValues),
            true,
            DUMMY_STACK);

    // Create another rule
    attributeValues = new HashMap<>();
    attributeValues.put("name", "rule2");
    attributeValues.put("outs", ImmutableList.of("out2.txt"));
    attributeValues.put("cmd", "echo");

    Rule rule2 =
        RuleFactory.createAndAddRule(
            pkgBuilder,
            ruleClass,
            new BuildLangTypedAttributeValuesMap(attributeValues),
            true,
            DUMMY_STACK);

    Package pkg = pkgBuilder.build();

    // Both rules should be in the package
    assertThat(pkg.getTarget("rule1")).isSameInstanceAs(rule1);
    assertThat(pkg.getTarget("rule2")).isSameInstanceAs(rule2);
  }

  /**
   * Test 16: Label format validation.
   *
   * <p>This test verifies that rule labels have the correct format with package and rule name.
   */
  @Test
  public void testRuleLabelFormat() throws Exception {
    Path myPkgPath = scratch.resolve("/workspace/mypackage/BUILD");
    Package.Builder pkgBuilder =
        newBuilder(PackageIdentifier.createInMainRepo("mypackage"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "myrule");
    attributeValues.put("outs", ImmutableList.of("out.txt"));
    attributeValues.put("cmd", "echo");

    RuleClass ruleClass = provider.getRuleClassMap().get("genrule");
    Rule rule =
        RuleFactory.createAndAddRule(
            pkgBuilder,
            ruleClass,
            new BuildLangTypedAttributeValuesMap(attributeValues),
            true,
            DUMMY_STACK);

    Label expectedLabel = Label.parseCanonical("//mypackage:myrule");
    assertThat(rule.getLabel()).isEqualTo(expectedLabel);
  }

  /**
   * Test 17: Rule kind metadata.
   *
   * <p>This test verifies that rule kind/type metadata is correctly set.
   */
  @Test
  public void testRuleKindMetadata() throws Exception {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
