    assertThat(rule.getRuleClass()).isEqualTo("genrule");
    assertThat(rule.getTargetKind()).isEqualTo("genrule rule");
  }

  /**
   * Test 18: Error reporting in rule creation.
   *
   * <p>This test verifies that rule creation errors are properly reported.
   */
  @Test
  public void testErrorReportingInRuleCreation() {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", null); // Invalid: null name
    attributeValues.put("outs", ImmutableList.of("out.txt"));
    attributeValues.put("cmd", "echo");

    RuleClass ruleClass = provider.getRuleClassMap().get("genrule");

    assertThrows(
        RuleFactory.InvalidRuleException.class,
        () ->
            RuleFactory.createAndAddRule(
                pkgBuilder,
                ruleClass,
                new BuildLangTypedAttributeValuesMap(attributeValues),
                true,
                DUMMY_STACK));
  }

  /**
   * Test 19: Multiple attributes validation.
   *
   * <p>This test verifies that multiple attributes can be validated simultaneously.
   */
  @Test
  public void testMultipleAttributesValidation() throws Exception {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "complex_rule");
    attributeValues.put("srcs", ImmutableList.of(":source.cc"));
    attributeValues.put("hdrs", ImmutableList.of(":header.h"));
    attributeValues.put("copts", ImmutableList.of("-O2"));
    attributeValues.put("linkopts", ImmutableList.of("-lpthread"));

    RuleClass ruleClass = provider.getRuleClassMap().get("cc_library");
    Rule rule =
        RuleFactory.createAndAddRule(
            pkgBuilder,
            ruleClass,
            new BuildLangTypedAttributeValuesMap(attributeValues),
            true,
            DUMMY_STACK);

    AttributeMap attributes = RawAttributeMapper.of(rule);

    assertThat(attributes.get("srcs", BuildType.LABEL_LIST)).hasSize(1);
    assertThat(attributes.get("hdrs", BuildType.LABEL_LIST)).hasSize(1);
    assertThat(attributes.get("copts", BuildType.STRING_LIST)).hasSize(1);
    assertThat(attributes.get("linkopts", BuildType.STRING_LIST)).hasSize(1);
  }

  /**
   * Test 20: Rule callstack information.
   *
   * <p>This test verifies that rule location information is correctly preserved.
   */
  @Test
  public void testRuleLocationInformation() throws Exception {
    Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
    Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);

    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "located_rule");
    attributeValues.put("outs", ImmutableList.of("out.txt"));
    attributeValues.put("cmd", "echo");

    RuleClass ruleClass = provider.getRuleClassMap().get("genrule");
    Rule rule =
        RuleFactory.createAndAddRule(
            pkgBuilder,
            ruleClass,
            new BuildLangTypedAttributeValuesMap(attributeValues),
            true,
            DUMMY_STACK);

    // Verify location is from the outermost call (BUILD file)
    assertThat(rule.getLocation().file()).isEqualTo("BUILD");
    assertThat(rule.getLocation().line()).isEqualTo(42);
    assertThat(rule.getLocation().column()).isEqualTo(1);
  }
}

# StarlarkRuleEvalTest Implementation Guide

## Overview
This document explains how `StarlarkRuleEvalTest.java` tests the Starlark rule evaluation system in Bazel, including the interactions with `RuleFactory` and `RuleClass`.

## Architecture

### Key Components Tested

```
┌─────────────────────────────────────┐
│   StarlarkRuleEvalTest              │
│   (Test Suite)                      │
└────────────────┬────────────────────┘
                 │
         ┌───────┴───────┐
         ▼               ▼
    RuleFactory    RuleClass
    (factory)      (metadata)
         │               │
    ┌────┴─────┬─────────┴───┐
    ▼          ▼              ▼
  Rule      Package      Attribute
(instance) (container)  (definitions)
```

## Test Flow

### 1. Setup Phase
```java
// Create a test package context
Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
Package.Builder pkgBuilder = newBuilder(
    PackageIdentifier.createInMainRepo("mypkg"),
    myPkgPath);

// Get the rule class definition
RuleClass ruleClass = provider.getRuleClassMap().get("genrule");
```

**What happens:**
- `PackageLoadingTestCase` provides filesystem fixtures via `scratch`
- `PackageFactory` creates a builder for a new package
- `TestRuleClassProvider` gives access to Bazel's built-in rule classes

### 2. Configuration Phase
```java
// Prepare attribute values
Map<String, Object> attributeValues = new HashMap<>();
attributeValues.put("name", "my_genrule");
attributeValues.put("outs", ImmutableList.of("output.txt"));
attributeValues.put("cmd", "echo 'hello' > $@");

// Wrap in typed map
BuildLangTypedAttributeValuesMap typedAttrs =
    new BuildLangTypedAttributeValuesMap(attributeValues);
```

**What happens:**
- Attributes are collected in a standard Map
- Map is wrapped in `BuildLangTypedAttributeValuesMap` for type safety
- Values are stored in build-language types (before native conversion)

### 3. Creation Phase
```java
Rule rule = RuleFactory.createAndAddRule(
    pkgBuilder,           // Package being constructed
    ruleClass,            // Rule class definition (genrule)
    typedAttrs,           // Attribute values
    true,                 // failOnUnknownAttributes
    DUMMY_STACK);         // Call stack for location info
```

**What happens in RuleFactory.createAndAddRule():**

1. **Validate rule name** (RuleFactory.java:62-69)
   - Checks "name" attribute exists and is a string
   - Creates a Label from the name

2. **Validate rule placement** (RuleFactory.java:78-85)
   - Checks workspace-only rules are in WORKSPACE file
   - Checks build rules are in BUILD files

3. **Process generator attributes** (RuleFactory.java:87-99)
   - Adds generator_name/generator_function if needed
   - These track which macro/function created the rule

4. **Call RuleClass.createRule()** (RuleFactory.java:106)
   - RuleClass defines the rule structure and validates attributes
   - Converts build-language types to native types
   - Applies default attribute values
   - Creates the Rule instance

5. **Add to package** (RuleFactory.java:142)
   - Rule is added to the package being constructed
   - Package maintains target lookup by name

### 4. Verification Phase
```java
// Verify rule properties
assertThat(rule.getName()).isEqualTo("my_genrule");
assertThat(rule.getRuleClass()).isEqualTo("genrule");
assertThat(rule.containsErrors()).isFalse();

// Access rule from package
Package pkg = pkgBuilder.build();
assertThat(pkg.getTarget("my_genrule")).isSameInstanceAs(rule);
```

**What can be verified:**
- Rule metadata (name, class, location)
- Rule attributes (via `RawAttributeMapper`)
- Rule containment in package
- Rule visibility and other settings

## Detailed Test Explanations

### Test: Name Attribute Validation

```java
@Test
public void testMissingNameAttributeProducesError() {
    // 1. Setup
    Package.Builder pkgBuilder = newBuilder(...);

    // 2. Config - missing "name"
    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("outs", ImmutableList.of("output.txt"));
    attributeValues.put("cmd", "echo 'hello' > $@");

    // 3. Attempt creation - should fail
    RuleFactory.InvalidRuleException e = assertThrows(
        RuleFactory.InvalidRuleException.class,
        () -> RuleFactory.createAndAddRule(...));

    // 4. Verify error
    assertThat(e).hasMessageThat().contains("has no 'name' attribute");
}
```

**Code Path:**
- `RuleFactory.createAndAddRule()` → Line 63: `attributeValues.getAttributeValue("name")`
- Returns null → Line 64-65: Throws InvalidRuleException
- Error message: "genrule rule has no 'name' attribute"

### Test: Invalid Rule Names

```java
@Test
public void testInvalidRuleNames() {
    String[] invalidNames = {"my-rule", "my rule", "my.rule"};

    for (String name : invalidNames) {
        Map<String, Object> attrs = new HashMap<>();
        attrs.put("name", name);  // Invalid name format

        RuleFactory.InvalidRuleException e = assertThrows(
            RuleFactory.InvalidRuleException.class,
            () -> RuleFactory.createAndAddRule(...));

        assertThat(e).hasMessageThat().contains("illegal rule name");
    }
}
```

**Code Path:**
- `RuleFactory.createAndAddRule()` → Line 69: `String name = (String) nameObject;`
- Line 71-76: `pkgBuilder.createLabel(name)` → Throws LabelSyntaxException
- Exception caught and wrapped: "illegal rule name: my-rule: ..."

### Test: Attribute Type Validation

```java
@Test
public void testAttributeTypeValidation() throws Exception {
    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "typed_rule");
    attributeValues.put("cmd", "echo hello");        // String
    attributeValues.put("outs", ImmutableList.of(...)); // List

    Rule rule = RuleFactory.createAndAddRule(...);

    // Verify types after creation
    AttributeMap attributes = RawAttributeMapper.of(rule);
    assertThat(attributes.get("cmd", Type.STRING)).isEqualTo("echo hello");
    assertThat(attributes.get("outs", BuildType.OUTPUT_LIST)).hasSize(2);
}
```

**Code Path:**
1. Attributes passed to `RuleFactory.createAndAddRule()` as build-language types
2. `RuleClass.createRule()` converts each attribute using `BuildType.convertFromBuildLangType()`
3. Conversions:
   - String → String (no conversion)
   - ImmutableList → List<Label> (for label lists)
   - ImmutableList → List<String> (for string lists)
4. `RawAttributeMapper` allows retrieving attributes with type checking

### Test: Default Attributes

```java
@Test
public void testDefaultAttributeValuesAreApplied() throws Exception {
    Map<String, Object> attributeValues = new HashMap<>();
    attributeValues.put("name", "my_cc_library");
    // Don't provide optional attributes

    Rule rule = RuleFactory.createAndAddRule(...);

    AttributeMap attributes = RawAttributeMapper.of(rule);
    // alwayslink defaults to false
    assertThat(attributes.get("alwayslink", Type.BOOLEAN)).isFalse();
    // srcs defaults to empty list
    assertThat(attributes.get("srcs", BuildType.LABEL_LIST)).isEmpty();
}
```

**Code Path:**
1. `RuleFactory.createAndAddRule()` → `RuleClass.createRule()` → Line 106
2. `RuleClass.createRule()` iterates through all attributes
3. For missing optional attributes, `Attribute.getDefaultValue()` is called
4. Defaults are defined in RuleClass.Builder with `.value()` or computed functions
5. Example: `attr("alwayslink", BOOLEAN).value(false)` sets default to false

